def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(1, a + 5):
                    term1 = ((ratio - a) ** 6) / (a * b * 0.85 + 1)
                    term2 = np.sin(ratio * b / (a + 2))
                    priority += term1 * term2 + np.tanh(term1 - term2)
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 1.7
        elif 5 < ratio <= 8:
            for m in range(2, int(np.ceil(ratio)) + 5):
                for n in range(1, m + 4):
                    term = ((ratio - m) ** 4) * np.cos(ratio * m) / (n + 0.3)
                    priority += np.sin(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.5
        elif 3 <= ratio <= 5:
            s1 = 0
            s2 = 0
            for r in range(1, 15):
                s1 += ((ratio - 3) ** r) / (r * 2.2) * np.cos(r * ratio)
                s2 += ((ratio - 3) ** r) / (r * 1.5) * np.sin(r * ratio * 0.5)
            priority = (s1 * np.cos(8 * ratio) + s2 * np.sin(5 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2
        elif 1.2 <= ratio < 3:
            s3 = 0
            for n in range(1, 14):
                s3 += ((3 - ratio) ** n) / (n ** 2 + 1)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5.2
            else:
                penalty = np.cos(25 * ratio) * 3.2
            priority = s3 + penalty + np.exp(-1.7 / (ratio + 0.1))
            for x in range(1, 7):
                priority += np.sin(x * ratio * i * 0.8) * ((ratio - 1.2) ** x) / x
        elif 0.5 <= ratio < 1.2:
            s4 = 0
            for n in range(1, 18):
                s4 += ((1.2 - ratio) ** n) / (n * 3.5)
            priority = s4
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.8
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1.2 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.5:
            s5 = 0
            for k in range(1, 14):
                s5 += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s5 + 1 / (bin_cap + 4)
            if int(item * 1.8) % 5 == 0:
                priority *= 3
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4.2
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.5)
        else:
            s6 = 0
            for t in range(1, 12):
                s6 += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s6 + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.55:
            priority += np.log1p(item ** 2.2 * bin_cap) * 6.7
            for zz in range(1, 4):
                priority += np.sin(ratio * i * zz) * 1.1
        elif bin_cap > item * 3.0:
            priority -= np.exp(-3.5 * ratio) * 4.7
            for zz in range(1, 5):
                priority -= np.cos(ratio * i * zz) * 0.85
        for idx in range(1, 5):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.45
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.5) * 0.75
        else:
            priority -= np.cos(ratio * i * 1.5) * 0.65
        priorities[i] = priority
    return priorities
